"""
This is the main module to launch the program
"""

class Piece:
    def __init__(self, color, king=False):
        self.color = color
        self.king = king

    def promote_to_king(self):
        self.king = True

    def __str__(self):
        return "K" if self.king else "p"

class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        colors = ['b', 'w']
        for row in range(3):
            for col in range(len(colors)):
                if (row + col) % 2 == 1:
                    self.board[row][col] = Piece(colors[(row + col) % 2])
        for row in range(5, 8):
            for col in range(len(colors)):
                if (row + col) % 2 == 1:
                    self.board[row][col] = Piece(colors[not ((row + col) % 2)])

    def display_board(self):
        for row in self.board:
            print(" ".join(str(piece) if piece else "." for piece in row))

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'w'

    def switch_player(self):
        self.current_player = 'b' if self.current_player == 'w' else 'w'

    def make_move(self, from_pos, to_pos):
        row_from, col_from = from_pos
        row_to, col_to = to_pos

        piece = self.board.board[row_from][col_from]
        if not piece or piece.color != self.current_player:
            return False

        # Check for valid move and capture
        if (abs(row_from - row_to) == 2 and abs(col_from - col_to) == 2) and \
                self.is_capture_move(from_pos, to_pos):
            captured_row = (row_from + row_to) // 2
            captured_col = (col_from + col_to) // 2
            self.board.board[captured_row][captured_col] = None

        piece.king = True if abs(row_to - 0) == 7 or abs(row_to - 7) == 1 else piece.king
        self.board.board[row_from][col_from] = None
        self.board.board[row_to][col_to] = piece
        self.switch_player()
        return True

    def is_capture_move(self, from_pos, to_pos):
        row_from, col_from = from_pos
        row_to, col_to = to_pos
        direction = (row_to - row_from) / abs(row_to - row_from), (col_to - col_from) / abs(col_to - col_from)

        if self.board.board[int(row_from + direction[0])][int(col_from + direction[1])] is None:
            return False

        next_piece_row, next_piece_col = int(row_from + 2 * direction[0]), int(col_from + 2 * direction[1])
        if not (0 <= next_piece_row < 8 and 0 <= next_piece_col < 8):
            return False

        return self.board.board[next_piece_row][next_piece_col] is None

    def check_winner(self):
        # Check for draw or winner
        pass

if __name__ == "__main__":
    game = Game()
    while True:
        game.board.display_board()
        move_from = input(f"Player {game.current_player}, enter your move (from-to): ").split('-')
        if len(move_from) != 2:
            print("Invalid move format. Please use 'row-col' for both positions.")
            continue
        from_pos = tuple(map(int, move_from[0].strip()))
        to_pos = tuple(map(int, move_from[1].strip()))

        if not game.make_move(from_pos, to_pos):
            print("Invalid move. Try again.")
            continue

        winner = game.check_winner()
        if winner:
            print(f"Player {winner} wins!")
            break
